// MessagingContext.js
import React, { createContext, useContext, useState } from 'react';
import { MESSAGE_THREADS } from './data/mockEmployerData';

const MessagingContext = createContext(null);

export function MessagingProvider({ children }) {
  const [threads, setThreads] = useState(MESSAGE_THREADS);

  const sendMessage = (threadId, text, from) => {
    const newMsg = { id: 'm' + Date.now(), from, text, time: new Date().toISOString() };
    setThreads(ts => ts.map(t =>
      t.id === threadId
        ? { ...t, messages: [...t.messages, newMsg], lastMessage: text, lastTime: newMsg.time, unread: from === 'employer' ? 0 : t.unread }
        : t
    ));
  };

  const markThreadRead = (threadId) =>
    setThreads(ts => ts.map(t => t.id === threadId ? { ...t, unread: 0 } : t));

  const totalUnread = threads.reduce((s, t) => s + t.unread, 0);

  return (
    <MessagingContext.Provider value={{ threads, sendMessage, markThreadRead, totalUnread }}>
      {children}
    </MessagingContext.Provider>
  );
}

export const useMessaging = () => useContext(MessagingContext);
